  ('police-3218f787-moex-00001', 'police-3218f787', 'police-3218f787-moex-114-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '依我國憲法規定人民受逮捕拘禁時，逮捕拘禁機關至遲多久應移送該管法院審問？', '["48小時", "36小時", "24小時", "12小時"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:09+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "505", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00002', 'police-3218f787', 'police-3218f787-moex-114-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '依憲法及司法院大法官解釋，下列何者並非憲法上之法官？', '["檢察官", "地方法院簡易庭法官", "大法官", "懲戒法院法官"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:09+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "505", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00003', 'police-3218f787', 'police-3218f787-moex-114-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '依司法院大法官解釋，大陸地區人民於臺灣地區設籍未滿 10 年者，不得擔任公務人員之規 定，並未牴觸憲法，下列敘述何者錯誤？', '["立法者制定規範時應斟酌事物本質的差異而為合理的區別對待，以實現憲法價值", "法律得基於原大陸地區人民對自由民主憲政體制的認識與其他臺灣人民可能不同，限制其 任公職之權利", "此類爭議涉及兩岸政治事務，故對於代表民意且充分掌握資訊的立法機關，司法機關應完 全尊重其決定", "設籍10年始得任公職的限制，仍在必要及合理的範圍"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:09+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "505", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
