  ('police-3218f787-moex-00005', 'police-3218f787', 'police-3218f787-moex-114-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '關於憲法法庭，下列敘述何者錯誤？', '["憲法法庭之判決得不經言詞辯論", "憲法法庭之不受理裁定毋須標示主筆大法官", "憲法法庭之判決，應經全體大法官三分之二以上同意", "對於憲法法庭之裁判，不得聲明不服"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:09+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "505", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
